# @cctt_verify {"v":2,"sym":"sympy.utilities.tests.test_wester.test_U9","kind":"function","src_hash":"010985f75ff62d6d","in":{"base":"Any"},"out":{"base":"Any","pred":"result satisfies: s3 == (x + y) * Subs(Derivative(g(x), x), x, x ** 2 + y ** 2) * 2"},"spec":{"lhs":"test_U9()","rhs":"s3 == (x + y) * Subs(Derivative(g(x), x), x, x ** 2 + y ** 2) * 2","over":{"base":"Any"},"name":"test_U9_correct"},"guarantee":"s3 == (x + y) * Subs(Derivative(g(x), x), x, x ** 2 + y ** 2) * 2","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.utilities.tests.test_wester.test_U9_correct","statement":"Path(test_U9(x), s3 == (x + y) * Subs(Derivative(g(x), x), x, x ** 2 + y ** 2) * 2)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"3df551f467d8331b","spec_source":"static","formal_spec":{"source":"static","strength":"formal","ensures":["s3 == (x + y) * Subs(Derivative(g(x), x), x, x ** 2 + y ** 2) * 2"],"pure":true},"c4_verdict":{"valid":true,"n_vcs":1,"n_verified":0,"n_assumed":1,"n_failed":0,"trust_level":"LIBRARY_ASSUMED","compile_ms":0.1,"verdict_class":"assumed","binding":true}}
def test_U9():
    # Wester sample case for Maple:
    # O29 := diff(f(x, y), x) + diff(f(x, y), y);
    #                      /d         \   /d         \
    #                      |-- f(x, y)| + |-- f(x, y)|
    #                      \dx        /   \dy        /
    #
    # O30 := factor(subs(f(x, y) = g(x^2 + y^2), %));
    #                                2    2
    #                        2 D(g)(x  + y ) (x + y)
    x, y = symbols('x y', real=True)
    su = diff(f(x, y), x) + diff(f(x, y), y)
    s2 = su.subs(f(x, y), g(x**2 + y**2))
    s3 = s2.doit().factor()
    # Subs not performed, s3 = 2*(x + y)*Subs(Derivative(
    #   g(_xi_1), _xi_1), _xi_1, x**2 + y**2)
    # Derivative(g(x*2 + y**2), x**2 + y**2) is not valid in SymPy,
    # and probably will remain that way. You can take derivatives with respect
    # to other expressions only if they are atomic, like a symbol or a
    # function.
    # D operator should be added to SymPy
    # See https://github.com/sympy/sympy/issues/4719.
    assert s3 == (x + y)*Subs(Derivative(g(x), x), x, x**2 + y**2)*2


